$:/plugins/kookma/thinkup/comments/style.text:
\rules only filteredtranscludeinline transcludeinline macrodef macrocallinline
.tc-is-comment-header {
	padding:0.25em;
	margin-top:0.5em;
	margin-bottom:1em; /* prevent overlap with smart-tabs */
  border-radius: 4px;
/*	border: 2px solid #c1e1ea;
	background: #f1fcff; */
	border: 2px solid <<color tab-border>>;
	background: <<color tiddler-editor-background>>;
}

/*
.tc-comments-segment {
	border-top: 2px solid #d7eef4;
}
*/

.tc-comment-button button {
	width: 100%;
	text-align: right;
}

.tc-sidebar-scrollable .tc-comment-button button {
	width: auto;
	text-align: right;
}

.tc-comment-button button svg {
/*	fill: #26cb56;*/
   fill: <<color tiddler-controls-foreground>>;
   height: 1.5em;  /* by mohammad */
   width: 1.5em;
}

/* Mohammad --------------*/
.tc-comment-button:hover button svg{
fill: <<color tiddler-controls-foreground-hover>> ;
}

.tc-comments {}

.tc-comment-list {
	list-style: none;
     padding-left: 0;
}

.tc-comment-list .tc-comments {
	padding-left: 1em;
}

.tc-comment-entry {
	position: relative;
	border-radius: 4px;
	margin: 0.5em 0 0 0;
/* background: #f1fcff;*/
/* border: 2px solid #c1e1ea; */
	border: 2px solid <<color tab-border>>;
	background: <<color tiddler-editor-background>>;
}

.tc-comment-entry-heading {
	font-size: 0.7em;
	font-weight: bold;
	text-transform: uppercase;
/*	background: #d7eef4;
	color: #5B6D80; */
	background: <<color tab-background>>;
  color: <<color tab-foreground>>;
	padding: 0 0.5em;
}

.tc-comment-entry-body {
	font-size: 0.8em; /* affects view mode and toolbars in edit mode */
	line-height:1.25em;
	padding: 0 0.5em;
}

/* font size of comment editor */
.tc-comment-entry-body textarea {
	font-size: 0.9em;
	width: 100%;
  min-height: 40px;
  resize: vertical; /*  user can resize vertically, but width is fixed */
}

.tc-comment-entry-body .CodeMirror { /* if CodeMirror is in use */
	font-size: 1.2em;
}

/* To work with Kara plugin: to prevent duplicates for checklist and interstitial */
.tc-comment-entry-body p.todo,
.tc-comment-entry-body ul.interstitial{
	display:none;
}

$:/plugins/kookma/thinkup/journalbook/st.text:
.kk-thinkup-jb-container {
	display: grid;
	grid-template-columns: 100px 1fr;
	grid-gap: 20px;
}
.kk-thinkup-jb-container aside {
	border-right: 1px solid #999;
	padding-left:5px;
}
.tc-btn-invisible.kk-thinkup-jb-selected{
	color:<<color alert-highlight>>;
}

.kk-thinkup-jb-item{
	padding-left:10px;
}

$:/plugins/kookma/thinkup/styles/searchb.text:
.search-box {
  border:none;
  border-bottom:1px solid #ccc;
  outline-style: none;
  width:20em
}

.search-box::placeholder {
  font-size: 0.9em;
	color: <<color muted-foreground>>
}

.search-box label{display:block;}

$:/plugins/kookma/thinkup/styles/setting.text:
.thinkup-stab-enablefilter {
border:none;
border-bottom:1px dotted <<color border>>;
min-width:35ch;
padding-bottom:5px;
color: <<color foreground>>;
}
.thinkup-stab-enablefilter:disabled{
color: <<color muted-foreground>>;
}

$:/plugins/kookma/thinkup/styles/stabs.text:
/* Style tab links ....................................*/
.thinkup-tab-set .thinkup-tab-buttons{
	display:flex;
	justify-content: flex-end;
}

.thinkup-tab-set .tab-button {
	border: none;
	outline: none;
	font-size: 0.85em;
	margin-left:4px;
}

.thinkup-tab-set .tab-button svg{
	height:1.5em;
	width:1.5em;
	fill: <<color tiddler-controls-foreground>>;
}
.thinkup-tab-set .tab-button:hover svg{
	fill: <<color tiddler-controls-foreground-hover>>;
}

/* Style selected tab  */
.thinkup-tab-set button.selected svg{
	fill: <<color tiddler-controls-foreground-hover>>;
}
.thinkup-tab-set .selected {
	/*	background-color:lavender;*/
}

/* Style the tab divider ...............................*/
.thinkup-tab-divider{/* for future*/}

/* Style the tab content ...............................*/
.thinkup-tab-set .tab-content {
	display: none;
	padding: 10px 5px;

	border-top: 1px solid #d8d8d8;
	margin-top:2px;
}

/* selected tab*/
.thinkup-tab-set .tab-content {
	/*	background-color:lavender;*/
}

$:/plugins/kookma/thinkup/styles/task-do.text:
/* 
Button appears on the tiddlers tagged with Task 
through task viewtemplate
*/
.thinkup-task-row{
	margin-top:-20px;
	display: flex; 
	flex-direction: row-reverse;
}

.thinkup-btn-task-done input{
	display : none;
}

.thinkup-task-row button,
.thinkup-btn-task-done input + span {
	border:1px solid <<colour tab-border>>;
	padding:2px 4px;
	border-radius:8px;
	font-size:0.8em;
}

.thinkup-task-row button,
.thinkup-btn-task-done input + span {
	cursor: pointer;
}

.thinkup-btn-task-done input:checked + span{}

.thinkup-btn-task-done svg,
.thinkup-task-info svg {
	height: 1em;
	width:  1em;
	margin-right: 3px;
	margin-bottom: 1px;
	vertical-align: middle;
}

.thinkup-task-row button{
  margin-left:0.5em;
}

$:/plugins/kookma/thinkup/styles/task-ex.text:
/* Task explorer dynamic table */
table.thinkup-task-explorer td {
	word-break: break-word;
}

/* the select widget on Task Explorer */
.thinkup-task-explorer-select{
	width: 5rem;
	border: 0;
	border-bottom:1px dotted;
	background-color:<<color tiddler-background>>;
	color:inherit;
}
.thinkup-task-explorer-select:focus{
	outline: none;
}

/* used only for subtitle of task tiddlers*/
.thinkup-task-explorer-select:hover,
.thinkup-task-explorer-select:focus{
color: <<color foreground>>;
}

$:/plugins/kookma/thinkup/styles/task-su.text:
/* customize the Pikaday calendar in Task subtitle */

.thinkup-task-info .py-btn{
	border-radius: inherit;
	border: inherit;
	color:inherit;
	padding:0;
}

.thinkup-task-info .py-overdue{
	font-weight:inherit;
	background:inherit;
	color:<<colour alert-highlight>>;
}

.thinkup-task-info .py-due-today{
	color:<<colour alert-muted-foreground>>;
}
.thinkup-task-info .py-due-today svg{
	fill:<<colour alert-muted-foreground>>;
}
